// JUnit 5 test class behavior simulation
public class AssertDemo {
    static void assertEquals(Object expected, Object actual) {
        if (!expected.equals(actual))
            throw new AssertionError("Expected " + expected + " but was " + actual);
    }
    static void assertTrue(boolean cond) {
        if (!cond) throw new AssertionError("Expected true");
    }
    public static void main(String[] args) {
        try { assertEquals("hello", "hello"); System.out.println("pass"); } catch(AssertionError e) { System.out.println("fail"); }
        try { assertEquals(1, 2); System.out.println("pass"); } catch(AssertionError e) { System.out.println("fail"); }
        try { assertTrue(5 > 3); System.out.println("pass"); } catch(AssertionError e) { System.out.println("fail"); }
    }
}
